import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

export function useComponent(props: Props): HookReturn {
  const { temperature, humidity, windSpeed, unit = 'C', condition } = props;

  return useMemo(() => {
    const unitLabel = `°${unit}`;
    const windUnit = unit === 'F' ? 'mph' : 'km/h';

    const iconMap: Record<string, string> = {
      'Sunny': '☀️',
      'Cloudy': '☁️',
      'Partly Cloudy': '⛅',
      'Rainy': '🌧️',
      'Thunderstorm': '⛈️',
      'Snowy': '❄️',
      'Mist': '🌫️',
      'Fog': '🌫️',
    };

    const conditionIcon = iconMap[condition] || '🌡️';

    return {
      formattedTemp: `${temperature}${unitLabel}`,
      formattedWind: `${windSpeed} ${windUnit}`,
      formattedHumidity: `${humidity}%`,
      conditionIcon,
      unitLabel,
    };
  }, [temperature, humidity, windSpeed, unit, condition]);
}


