/**
 * WeatherMetrics component displays humidity and wind speed in a horizontal row.
 * It uses semantic tokens for consistent theming and layout primitives for positioning.
 * 
 * @param humidity - Percentage of humidity (e.g., "45%")
 * @param windSpeed - Speed of wind with units (e.g., "12 km/h")
 */
export const WeatherMetrics: React.FC<WeatherMetricsProps> = ({
  humidity,
  windSpeed,
}) => {
  return (
    <Box paddingY={2}>
      {/* Main row wrapper using Stack as a Row primitive */}
      <Stack 
        direction="horizontal" 
        gap={4} 
        align="center" 
        justify="between"
        wrap={true}
      >
        {/* Humidity Section */}
        <Stack direction="horizontal" gap={8} align="center">
          <Icon 
            name="water_drop" 
            size={20} 
            color="var(--ggui-color-primary-600, #0284c7)" 
          />
          <Stack gap={0}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity
            </Text>
            <Text variant="body">
              {humidity}
            </Text>
          </Stack>
        </Stack>

        {/* Visual separation */}
        <Divider orientation="vertical" margin={4} />

        {/* Wind Speed Section */}
        <Stack direction="horizontal" gap={8} align="center">
          <Icon 
            name="air" 
            size={20} 
            color="var(--ggui-color-primary-600, #0284c7)" 
          />
          <Stack gap={0}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind Speed
            </Text>
            <Text variant="body">
              {windSpeed}
            </Text>
          </Stack>
        </Stack>
      </Stack>
    </Box>
  );
};

