import type { Props, HookReturn } from '/virtual/types';
import React from 'react';
import { Text, Heading } from '@ggui-ai/design/primitives';

export function MainView({ element, isSelected, isMatch, onClick }: ElementCellProps) {
  /**
   * Maps chemical categories to theme-aware background colors.
   */
  const getCategoryColor = (category: string) => {
    const cat = category.toLowerCase();
    if (cat.includes('alkali')) return 'var(--ggui-color-primary-100, #e0f2fe)';
    if (cat.includes('noble')) return 'var(--ggui-color-container, #ede9fe)';
    if (cat.includes('halogen')) return 'var(--ggui-color-warning-100, #fef3c7)';
    return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      onClick(element);
    }
  };

  return (
    <div
      role="button"
      tabIndex={0}
      aria-selected={isSelected}
      onClick={() => onClick(element)}
      onKeyDown={handleKeyDown}
      style={{
        // Grid coordinates from data (1-indexed)
        gridRow: element.row,
        gridColumn: element.col,
        // Visuals
        aspectRatio: '1 / 1',
        cursor: 'pointer',
        transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
        backgroundColor: getCategoryColor(element.category),
        border: isSelected 
          ? '2px solid var(--ggui-color-primary-500, #0ea5e9)' 
          : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
        borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
        // Search state: de-emphasize if not a match
        opacity: isMatch ? 1 : 0.3,
        position: 'relative',
        overflow: 'hidden',
        outline: 'none',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
        padding: 'var(--ggui-spacing-1, 4px)',
      }}
    >
      <div style={{ position: 'absolute', top: 4, left: 4 }}>
        <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {element.atomicNumber}
        </Text>
      </div>

      <Heading level={5} align="center">
        {element.symbol}
      </Heading>

      <div style={{ position: 'absolute', bottom: 4, left: 0, right: 0, padding: '0 4px' }}>
        <Text 
          variant="caption" 
          align="center" 
          truncate 
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {element.name}
        </Text>
      </div>
    </div>
  );
}


