          </Stack>
          <Stack gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
            <Text variant="bodyLarge" weight="semibold">
              {selectedElement.atomicWeight.toFixed(3)}
            </Text>
          </Stack>
          <Stack gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Period</Text>
            <Text variant="bodyLarge" weight="semibold">{selectedElement.row}</Text>
          </Stack>
          <Stack gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Group</Text>
            <Text variant="bodyLarge" weight="semibold">{selectedElement.col}</Text>
          </Stack>
        </Stack>
      </Stack>
