import type { Props, HookReturn } from '/virtual/types';
import React from 'react';
import { Row, Box, Text } from '@ggui-ai/design/primitives';

const getCategoryColor = (category: string) => {
  switch (category.toLowerCase()) {
    case 'alkali-metal': return 'var(--ggui-color-error-100, #fee2e2)';
    case 'alkaline-earth-metal': return 'var(--ggui-color-warning-100, #fef3c7)';
    case 'transition-metal': return 'var(--ggui-color-container, #ede9fe)';
    case 'lanthanide': return 'var(--ggui-color-primary-100, #e0f2fe)';
    case 'actinide': return 'var(--ggui-color-primary-200, #bae6fd)';
    case 'post-transition-metal': return 'var(--ggui-color-success-100, #dcfce7)';
    case 'metalloid': return 'var(--ggui-color-info-100, #ecfeff)';
    case 'polyatomic-nonmetal': return 'var(--ggui-color-success-200, #bbf7d0)';
    case 'diatomic-nonmetal': return 'var(--ggui-color-info-200, #a5f3fc)';
    case 'noble-gas': return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
    default: return 'var(--ggui-color-outline, #d4d4d8)';
  }
};

const formatCategory = (category: string) => {
  return category
    .split('-')
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
};

export function MainView(props: LegendProps) {
  const { categories } = props;

  if (!categories || categories.length === 0) return null;

  return (
    <Row 
      wrap={true} 
      gap="var(--ggui-spacing-4, 16px)"
      style={{
        padding: 'var(--ggui-spacing-4, 16px)',
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      }}
    >
      {categories.map((category) => (
        <Row key={category} align="center" gap="var(--ggui-spacing-2, 8px)">
          <Box
            style={{
              width: 16,
              height: 16,
              borderRadius: 'var(--ggui-spacing-1, 4px)',
              background: getCategoryColor(category),
            }}
          />
          <Text variant="bodySmall">
            {formatCategory(category)}
          </Text>
        </Row>
      ))}
    </Row>
  );
}


