import type { Props, HookReturn } from '/virtual/types';
// components/index.tsx — main component composing sub-components
import React from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

export function MainView(props: PeriodicTableProps & HookReturn) {
  const { 
    elements,
    searchQuery, 
    setSearchQuery, 
    selectedElement, 
    setSelectedElement, 
    filteredElements, 
    categories 
  } = props;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header and Search */}
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={1} align="center">Periodic Table of Elements</Heading>
          <Box margin="0 auto" style={{ maxWidth: '600px', width: '100%' }}>
            <SearchField
              value={searchQuery}
              onChange={setSearchQuery}
              placeholder="Search by name, symbol, or atomic number..."
              size="lg"
            />
          </Box>
        </Stack>

        {/* Periodic Table Grid */}
        <Stack gap="var(--ggui-spacing-6)">
          <Box 
            style={{ 
              overflowX: 'auto',
              padding: 'var(--ggui-spacing-2)',
              backgroundColor: 'var(--ggui-color-surfaceVariant)',
              borderRadius: 'var(--ggui-shape-radius-lg)',
              boxShadow: 'var(--ggui-shape-shadow-sm)'
            }}
          >
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(45px, 1fr))',
                gridAutoRows: 'minmax(60px, auto)',
                gap: 'var(--ggui-spacing-1)',
                minWidth: '900px'
              }}
            >
              {elements.map((element) => (
                <ElementCell
                  key={element.atomicNumber}
                  element={element}
                  isSelected={selectedElement?.atomicNumber === element.atomicNumber}
                  isMatch={searchQuery.length > 0 && filteredElements.some(e => e.atomicNumber === element.atomicNumber)}
                  onClick={setSelectedElement}
                />
              ))}
            </Box>
          </Box>

          <Legend categories={categories} />
        </Stack>

        {/* Detail Panel */}
        <Box>
          <DetailPanel element={selectedElement} />
        </Box>
      </Stack>
    </Container>
  );
}


