// --- hooks.ts ---
// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useMemo, useCallback } from 'react';

// ── Action Handlers (from actionsSpec) ──────────────────
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}

export function useComponent(props: Props): HookReturn {
  const [currentStep, setCurrentStep] = useState(1);

  const [formData, setFormData] = useState<ProfileData>(() => ({
    name: props.initialProfile?.name ?? "",
    email: props.initialProfile?.email ?? "",
    avatar: props.initialProfile?.avatar ?? props.avatarOptions?.[0] ?? "",
    role: props.initialProfile?.role ?? "",
    emailNotifications: props.initialProfile?.emailNotifications ?? true,
    theme: props.initialProfile?.theme ?? "light",
  }));

  const isStepValid = useMemo(() => {
    if (currentStep === 1) {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      return !!(formData.name.trim() && formData.avatar && emailRegex.test(formData.email));
    }
    if (currentStep === 2) {
      return !!formData.role;
    }
    return true;
  }, [currentStep, formData]);

  const progress = useMemo(() => {
    if (currentStep === 1) return 33;
    if (currentStep === 2) return 66;
    return 100;
  }, [currentStep]);

  const updateField = useCallback(<K extends keyof ProfileData>(field: K, value: ProfileData[K]) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  }, []);

  const nextStep = useCallback(() => {
    setCurrentStep(prev => Math.min(prev + 1, 3));
  }, []);

  const prevStep = useCallback(() => {
    setCurrentStep(prev => Math.max(prev - 1, 1));
  }, []);

  const submit = useCallback(() => {
    props.onComplete(formData);
  }, [props.onComplete, formData]);

  return {
    currentStep,
    formData,
    progress,
    isStepValid,
    handlers: {
      nextStep,
      prevStep,
      updateField,
      submit,
    },
  };
}


