// --- components/StepControls.tsx ---
// Path: /virtual/components/StepControls.tsx
import React from 'react';
import { Box, Divider, Stack, Button } from '@ggui-ai/design/primitives';
import { StepControlsProps } from '/virtual/types';

export const StepControls: React.FC<StepControlsProps> = ({
  currentStep,
  totalSteps,
  isValid,
  onNext,
  onBack,
  onSubmit,
}) => {
  const isFirstStep = currentStep === 1;
  const isLastStep = currentStep === totalSteps;

  return (
    <Box margin="var(--ggui-spacing-6) 0 0 0">
      <Divider margin="var(--ggui-spacing-6)" />

      <Stack direction="horizontal" justify="between" align="center">
        <Box>
          {!isFirstStep && (
            <Button variant="outline" onClick={onBack}>
              Back
            </Button>
          )}
        </Box>

        <Button
          variant="primary"
          onClick={isLastStep ? onSubmit : onNext}
          disabled={!isValid}
        >
          {isLastStep ? 'Complete Setup' : 'Next'}
        </Button>
      </Stack>
    </Box>
  );
};

// --- components/index.tsx ---
// Path: /virtual/components/index.tsx
import type { Props, HookReturn } from '/virtual/types';
// components/index.tsx — main component composing sub-components
import React from 'react';
import { Container, Card, Stack, Box, MotionKeyframes } from '@ggui-ai/design/primitives';

export function MainView(props: ProfileWizardProps & HookReturn) {
  const { currentStep, formData, progress, isStepValid, handlers } = props;
  const TOTAL_STEPS = 3;

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="xl">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          <StepIndicator
            currentStep={currentStep}
            totalSteps={TOTAL_STEPS}
            progress={progress}
          />

          <Box style={{ minHeight: '400px', animation: 'ggui-fadeIn 300ms ease-out' }}>
            {currentStep === 1 && (
              <StepProfile
                data={formData}
                avatarOptions={props.avatarOptions}
                onChange={handlers.updateField}
              />
            )}
            {currentStep === 2 && (
              <StepPreferences
                data={formData}
                roleOptions={props.roleOptions}
                onChange={handlers.updateField}
              />
            )}
            {currentStep === 3 && (
              <StepReview data={formData} />
            )}
          </Box>

          <StepControls
            currentStep={currentStep}
            totalSteps={TOTAL_STEPS}
            isValid={isStepValid}
            onNext={handlers.nextStep}
            onBack={handlers.prevStep}
            onSubmit={handlers.submit}
          />
        </Stack>
      </Card>
    </Container>
  );
}


